mapper.insert:
/* [insertChatApiLog] 외부 API 송수신 로그 등록 */
INSERT INTO CHAT_API_LOG
       ( COMPANY_CODE
       , LOG_KEY
       , VENDOR
       , HTTP_METHOD
       , API_PATH
       , API_BASE_URL
       , API_FULL_URL
       , REQUEST_DT
       , REQUEST_HEADER
       , REQUEST_QUERY_STRING
       , REQUEST_BODY
       , RESPONSE_DT
       , RESPONSE_STATUS_CODE
       , RESPONSE_HEADER
       , RESPONSE_BODY
       , RESPONSE_BODY_SIZE
       , RESPONSE_TIME_MS
       , CALL_STATUS
       , SUCCESS_YN
       , ERROR_YN
       , ERROR_MESSAGE
       , TIMEOUT_YN
       , FIRST_CREATE_USER_ID
       , CREATE_DT
       )
VALUES ( #{companyCode}
       , #{logKey}
       , #{vendor}
       , #{httpMethod}
       , #{apiPath}
       , #{apiBaseUrl}
       , #{apiFullUrl}
       , TO_TIMESTAMP(#{requestDt}, 'YYYY-MM-DD HH24:MI:SS')
       , 

               #{requestHeader}::jsonb


               NULL


       , #{requestQueryString}
       , 

               #{requestBody}::jsonb


               NULL


       , TO_TIMESTAMP(#{responseDt}, 'YYYY-MM-DD HH24:MI:SS')
       , #{responseStatusCode}
       , 

               #{responseHeader}::jsonb


               NULL


       , 

               #{responseBody}::jsonb


               NULL


       , #{responseBodySize}
       , #{responseTimeMs}
       , #{callStatus}
       , #{successYn}
       , #{errorYn}
       , #{errorMessage}
       , #{timeoutYn}
       , #{firstCreateUserId}
       , NOW()::timestamptz
       )

/* [insertChatApiFileLog] 외부 API 송수신 로그 파일 정보 등록 */
INSERT INTO CHAT_API_FILE_LOG
       ( COMPANY_CODE
       , LOG_KEY
       , FILE_LOG_KEY
       , FILE_NAME
       , FILE_SIZE
       , FILE_TYPE
       , MIME_TYPE
       , SUCCESS_YN
       , ERROR_MESSAGE
       , CREATE_DT
       )
VALUES ( #{companyCode}
       , #{logKey}
       , #{fileLogKey}
       , #{fileName}
       , #{fileSize}
       , #{fileType}
       , #{mimeType}
       , #{successYn}
       , #{errorMessage}
       , NOW()::timestamptz
       )

mapper.update:
/* [updateChatApiFileLog] 외부 API 송수신 로그 파일 정보 업데이트 */
UPDATE CHAT_API_FILE_LOG
   SET SUCCESS_YN = #{successYn}
     , ERROR_MESSAGE = #{errorMessage}
 WHERE COMPANY_CODE = #{companyCode}
   AND FILE_LOG_KEY = #{fileLogKey}

/* [updateChatApiFileLogKey] 외부 API 송수신 로그 파일 정보 logKey 업데이트 */
UPDATE CHAT_API_FILE_LOG
   SET LOG_KEY = #{logKey}
 WHERE COMPANY_CODE = #{companyCode}
   AND FILE_LOG_KEY = #{fileLogKey}
   AND LOG_KEY = ''
